class Solution:
    def subarrayGCD(self, nums: List[int], k: int) -> int:
        count = 0
        for i in range(len(nums)):
            for j in range(i+1, len(nums)):
                if gcd(nums[i], nums[j]) == k:
                    count += len(set(nums[i:j+1]))
        return count

def gcd(a, b):
    while b:
        a, b = b, a % b
    return a
```

